    <!-- Decorative line -->
    <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 16px;">
      <div style="width: 50px; height: 1px; background: linear-gradient(90deg, transparent, rgba(255,215,0,0.6));"></div>
      <div style="width: 8px; height: 8px; border: 1px solid #ffd700; transform: rotate(45deg);"></div>
      <div style="width: 50px; height: 1px; background: linear-gradient(90deg, rgba(255,215,0,0.6), transparent);"></div>
    </div>

